```python
class Config:
    """Over-engineered configuration."""

    def __init__(self, port: int) -> None:
        self._port = port  # Private backing field

    @property
    def port(self) -> int:
        """Unnecessary property - just returns stored value."""
        return self._port  # No computation, validation, or logic!

# BAD: Every access pays function call overhead for no benefit
print(config.port)  # Slower than direct attribute access
```

```python
class Circle:
    """Circle with radius and computed area."""

    def __init__(self, radius: float) -> None:
        self.radius = radius  # Public - simple stored value

    @property
    def area(self) -> float:
        """Computed value - appropriate use of @property."""
        return 3.14159 * self.radius ** 2
```

```python
class Server:
    """Server with port validation."""

    def __init__(self, port: int) -> None:
        self.port = port  # Triggers setter validation

    @property
    def port(self) -> int:
        return self._port

    @port.setter
    def port(self, value: int) -> None:
        """Validate port range."""
        if not (1024 <= value <= 65535):
            raise ValueError(f"Port must be 1024-65535, got {value}")
        self._port = value
```

```python from dataclasses import dataclass
@dataclass(frozen=True) class Config: """Simple configuration with public immutable attributes.""" host: str port: int timeout_seconds: float = 30.0
# Usage - direct access, zero overhead config = Config(host="localhost", port=8080) print(config.port) # Direct attribute access ```

Public attributes can be refactored to properties later without breaking callers:
```python
# Version 1: Simple public attribute
class User:
    def __init__(self, email: str) -> None:
        self.email = email

# Version 2: Refactored to property with validation (callers unchanged!)
class User:
    def __init__(self, email: str) -> None:
        self.email = email  # Still works - triggers setter

    @property
    def email(self) -> str:
        return self._email

    @email.setter
    def email(self, value: str) -> None:
        if "@" not in value:
            raise ValueError("Invalid email")
        self._email = value
```
